const express = require('express');
const twilio = require('twilio')(accountSid, authToken);

const app = express();

app.use(express.json());

// Generate random 6-digit code and send via SMS using Twilio
app.post('/send-code', (req, res) => {
  const code = Math.floor(100000 + Math.random() * 900000);
  twilio.messages.create({
    body: `Your verification code is ${code}.`,
    to: req.body.phoneNumber,
    from: '+1234567890' // Replace with your Twilio number
  });
  res.sendStatus(200);
});

// Verify user input and store codes in memory with user sessions for validation
app.post('/verify-code', (req, res) => {
  const code = req.body.code;
  const sessionId = req.session.id;
  if (!code || !sessionId) {
    return res.status(401).send('Invalid request');
  }
  const storedCode = req.session.verificationCodes[sessionId];
  if (storedCode && code === storedCode) {
    delete req.session.verificationCodes[sessionId];
    res.status(200).send('Verified');
  } else {
    res.status(401).send('Invalid code');
  }
});